using System;
using System.Collections.Generic;
using System.Windows.Input;
using Microsoft.Maui.Controls;
using Microsoft.Maui.Dispatching;
using Xunit;

public class LeakTest
{
    const int N = 30;

    sealed class StubTimer : IDispatcherTimer
    {
        public TimeSpan Interval { get; set; }
        public bool IsRepeating { get; set; }
        public bool IsRunning { get; private set; }
        public event EventHandler? Tick;
        public void Start() => IsRunning = true;
        public void Stop() => IsRunning = false;
    }
    sealed class StubDispatcher : IDispatcher
    {
        public bool IsDispatchRequired => false;
        public bool Dispatch(Action action) { action(); return true; }
        public bool DispatchDelayed(TimeSpan delay, Action action) => true;
        public IDispatcherTimer CreateTimer() => new StubTimer();
    }
    sealed class StubDispatcherProvider : IDispatcherProvider
    {
        readonly IDispatcher _d = new StubDispatcher();
        public IDispatcher GetForCurrentThread() => _d;
    }

    static LeakTest() => DispatcherProvider.SetCurrent(new StubDispatcherProvider());

    // A long-lived / shared command that never changes. Simulates a command owned by a
    // singleton view-model or static holder that outlives the transient control.
    sealed class SharedCommand : ICommand
    {
        public event EventHandler? CanExecuteChanged;
        public bool CanExecute(object? parameter) => true;
        public void Execute(object? parameter) { }
        public void RaiseCanExecuteChanged() => CanExecuteChanged?.Invoke(this, EventArgs.Empty);
    }

    static void ForceGc()
    {
        for (int i = 0; i < 6; i++)
        {
            GC.Collect();
            GC.WaitForPendingFinalizers();
            GC.Collect();
        }
    }

    static int CountAlive(List<WeakReference> refs)
    {
        int alive = 0;
        foreach (var r in refs)
            if (r.IsAlive)
                alive++;
        return alive;
    }

    // scenario: 0 = Control (never assign command), 1 = Leaky (assign, detach, never unsubscribe),
    // 2 = Mitigation (assign then set command back to null before discard -> unsubscribes)
    static List<WeakReference> Run(int scenario, SharedCommand command,
        Func<byte[], ICommand?, object> make, Action<object> clearCommand)
    {
        var refs = new List<WeakReference>();
        for (int i = 0; i < N; i++)
        {
            var payload = new byte[1024 * 1024];
            object control = make(payload, scenario == 0 ? null : command);
            if (scenario == 2)
                clearCommand(control);
            refs.Add(new WeakReference(control));
            control = null!;
        }
        return refs;
    }

    static void Assert3(Func<byte[], ICommand?, object> make, Action<object> clearCommand)
    {
        var command = new SharedCommand();
        var controlRefs = Run(0, command, make, clearCommand);
        var leakyRefs = Run(1, command, make, clearCommand);
        var mitigationRefs = Run(2, command, make, clearCommand);
        ForceGc();
        int controlAlive = CountAlive(controlRefs);
        int leakyAlive = CountAlive(leakyRefs);
        int mitigationAlive = CountAlive(mitigationRefs);
        // Keep the shared command rooted across the measurement window.
        command.RaiseCanExecuteChanged();
        GC.KeepAlive(command);
        Assert.Equal(0, controlAlive);
        Assert.Equal(N, leakyAlive);
        Assert.Equal(0, mitigationAlive);
    }

    [Fact]
    public void SwipeItemView_Command_Leaks()
    {
        Assert3(
            (payload, cmd) =>
            {
                var v = new SwipeItemView { CommandParameter = payload };
                if (cmd != null)
                    v.Command = cmd;
                return v;
            },
            control => ((SwipeItemView)control).Command = null);
    }

    [Fact]
    public void BackButtonBehavior_Command_Leaks()
    {
        Assert3(
            (payload, cmd) =>
            {
                var b = new BackButtonBehavior { CommandParameter = payload };
                if (cmd != null)
                    b.Command = cmd;
                return b;
            },
            control => ((BackButtonBehavior)control).Command = null);
    }

    [Fact]
    public void ListView_RefreshCommand_Leaks()
    {
        Assert3(
            (payload, cmd) =>
            {
                var lv = new ListView { Header = payload };
                if (cmd != null)
                    lv.RefreshCommand = cmd;
                return lv;
            },
            control => ((ListView)control).RefreshCommand = null);
    }
}
