                ? (UIKit.NSMutableParagraphStyle)existingStyle.MutableCopy() 
                : new UIKit.NSMutableParagraphStyle();

            mutableStyle.MinimumLineHeight = targetLineHeight;
            mutableStyle.MaximumLineHeight = targetLineHeight;

            mutableAttr.AddAttribute(UIKit.UIStringAttributeKey.ParagraphStyle, mutableStyle, range);
        });

    uiLabel.AttributedText = mutableAttr;

